class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    from_account: Optional[str]
    to_account: Optional[str]
    amount: Decimal
